import time
import threading
import fnmatch
from collections import defaultdict, deque
from typing import Any, Callable, Optional, List, Dict
from concurrent.futures import ThreadPoolExecutor


class EventBus:
    def __init__(self, history_size: int = 100):
        self._subscribers: Dict[str, List[dict]] = defaultdict(list)
        self._history: Dict[str, deque] = defaultdict(lambda: deque(maxlen=history_size))
        self._lock = threading.Lock()
        self._executor = ThreadPoolExecutor(max_workers=4)
        self._stats = {'total_events': 0}

    def subscribe(self, topic: str, callback: Callable, filter_fn: Optional[Callable] = None) -> None:
        if not callable(callback):
            raise TypeError('Callback must be callable')
        if not isinstance(topic, str) or not topic:
            raise ValueError('Topic must be a non-empty string')
        with self._lock:
            self._subscribers[topic].append({
                'callback': callback,
                'filter_fn': filter_fn,
            })

    def unsubscribe(self, topic: str, callback: Callable) -> bool:
        with self._lock:
            subs = self._subscribers.get(topic, [])
            for i, sub in enumerate(subs):
                if sub['callback'] is callback:
                    subs.pop(i)
                    return True
            return False

    def _get_matching_subscribers(self, topic: str) -> list:
        matching = []
        for pattern, subs in self._subscribers.items():
            if pattern == topic or fnmatch.fnmatch(topic, pattern):
                matching.extend(subs)
        return matching

    def publish(self, topic: str, data: Any) -> int:
        timestamp = time.time()
        event = {'topic': topic, 'data': data, 'timestamp': timestamp}
        with self._lock:
            self._history[topic].append(event)
            self._stats['total_events'] += 1
            subscribers = self._get_matching_subscribers(topic)
        delivered = 0
        for sub in subscribers:
            if sub['filter_fn'] and not sub['filter_fn'](data):
                continue
            try:
                sub['callback'](topic, data, timestamp)
                delivered += 1
            except Exception:
                pass
        return delivered

    def publish_async(self, topic: str, data: Any) -> None:
        self._executor.submit(self.publish, topic, data)

    def get_subscribers(self, topic: str) -> List[Callable]:
        with self._lock:
            return [s['callback'] for s in self._subscribers.get(topic, [])]

    def history(self, topic: str, limit: int = 10) -> list:
        with self._lock:
            events = list(self._history.get(topic, []))
            return events[-limit:]

    def clear_topic(self, topic: str) -> None:
        with self._lock:
            self._subscribers.pop(topic, None)
            self._history.pop(topic, None)

    def stats(self) -> dict:
        with self._lock:
            total_subs = sum(len(s) for s in self._subscribers.values())
            return {
                'topic_count': len(self._subscribers),
                'total_subscribers': total_subs,
                'total_events': self._stats['total_events'],
            }
